=SELECT 
  numero_utilisateur,
  nom,
  prenom,
  email,
  LOWER(type_utilisateur) as role
FROM utilisateur 
WHERE type_utilisateur IN ({{ $json.roles.map(role => {
  const roleMapping = {
    'etudiant': 'ETUDIANT',
    'enseignant': 'ENSEIGNANT', 
    'directeur': 'DIRECTEUR',
    'recteur': 'RECTEUR'
  };
  return `'${roleMapping[role] || role.toUpperCase()}'`;
}).join(', ') }})
AND statut = 'ACTIF'
ORDER BY type_utilisateur, nom, prenom

